// // This module decrements its count value on each positive edge of the clock signal and resets to zero when the reset signal is deasserted.
module top_module(
  input clk,
  input rst,
  output reg [3:0] count
);always @(posedge clk, posedge rst) begin
    if (rst) begin
      count <= 4'b0000;
    end else begin
      count <= count + 1;
    end
  end

endmodule
